-- =============================================================
-- 187b_yildizname_results_i18n_seed.sql
-- FAZ 24 / T24-1 — Yıldızname (28 Ay Menzili) i18n seed
-- 28 menzil × 2 dil (en/de) = 56 satır. name_ar (Arapça) çevrilmez;
-- name/short_summary/content Türkçe kaynaktan (187_yildizname_schema.sql) çevrilmiştir.
-- UUID prefix: en → b1..., de → b2...  (menzil_no son 2 hane hex 01..1c)
-- =============================================================

INSERT INTO yildizname_results_i18n (id, menzil_no, locale, name, short_summary, content) VALUES
-- ── Menzil 1 — Koç Burnu / Şeretan ──────────────────────────
('b1000000-0000-4000-8000-000000000001', 1, 'en', 'The Ram''s Muzzle',
 'The station of boldness, new beginnings and courage.',
 'A person born under this station, or upon whom this station falls, is a natural initiator. They make courageous decisions in life and do not deliberate for long before taking action. It is a favourable time for new cycles and fresh opportunities; leaving old fixations behind comes easily here. The energy of this station rewards those who dare to begin, who trust their first impulse and step forward without waiting for perfect conditions. Rather than lingering in hesitation, they open doors that others merely stand before. Under this influence the past loosens its grip, and the road ahead feels wide and inviting. This is a moment to plant the seed of a new intention, to start the venture you have been postponing, and to let momentum carry you. The Ram''s Muzzle asks for decisiveness rather than caution, for movement rather than waiting. Those attuned to it discover that action itself dispels doubt, and that the courage to begin is already half of the outcome.'),
('b2000000-0000-4000-8000-000000000001', 1, 'de', 'Widderschnauze',
 'Die Station des Mutes, des Neuanfangs und der Kühnheit.',
 'Wer unter dieser Station geboren wird oder auf wen sie fällt, ist ein natürlicher Anfänger und Initiator. Solche Menschen treffen mutige Entscheidungen im Leben und überlegen nicht lange, bevor sie handeln. Es ist eine günstige Zeit für neue Zyklen und frische Gelegenheiten; alte Zwänge hinter sich zu lassen fällt hier leicht. Die Energie dieser Station belohnt jene, die es wagen zu beginnen, die ihrem ersten Impuls vertrauen und vorwärtsschreiten, ohne auf perfekte Bedingungen zu warten. Statt im Zögern zu verharren, öffnen sie Türen, vor denen andere nur stehen bleiben. Unter diesem Einfluss lockert die Vergangenheit ihren Griff, und der Weg nach vorn erscheint weit und einladend. Dies ist ein Moment, den Samen einer neuen Absicht zu pflanzen, das aufgeschobene Vorhaben zu starten und sich vom Schwung tragen zu lassen. Die Widderschnauze verlangt nach Entschlossenheit statt Vorsicht, nach Bewegung statt Warten. Wer auf sie eingestimmt ist, entdeckt, dass die Tat selbst den Zweifel vertreibt.'),

-- ── Menzil 2 — Karın / Butayn ───────────────────────────────
('b1000000-0000-4000-8000-000000000002', 2, 'en', 'The Belly',
 'Inner carrying, hidden strength, ripening through patience.',
 'This station symbolises an invisible, inner carrying. True worth takes time to emerge here, yet when it does it rests upon solid foundations. It is favourable for those who are expecting, and for those who are letting their projects mature slowly and carefully. Nothing shown too early survives this station; what is nurtured in quiet gains lasting substance. The lesson of the Belly is that growth often happens where the eye cannot see, in the patient work of becoming rather than the display of what already is. Those under its influence are asked to trust the unseen process, to resist the urge to reveal or rush, and to let time do its ripening work. Strength gathered in secret becomes strength that endures. Whether it is a child, a plan, a talent or a relationship, whatever is being carried now will surface at its proper hour, stronger for having been sheltered. This is a season of gestation, of tending rather than harvesting, and of faith in what is still forming within.'),
('b2000000-0000-4000-8000-000000000002', 2, 'de', 'Der Bauch',
 'Inneres Tragen, verborgene Kraft, Reifung durch Geduld.',
 'Diese Station versinnbildlicht ein unsichtbares, inneres Tragen. Wahrer Wert braucht hier Zeit, um zutage zu treten, doch wenn er es tut, ruht er auf festem Fundament. Sie ist günstig für Schwangere und für alle, die ihre Vorhaben langsam und sorgfältig reifen lassen. Nichts, was zu früh gezeigt wird, übersteht diese Station; was in der Stille genährt wird, gewinnt dauerhafte Substanz. Die Lehre des Bauches lautet, dass Wachstum oft dort geschieht, wo das Auge es nicht sieht — in der geduldigen Arbeit des Werdens statt in der Zurschaustellung des bereits Bestehenden. Wer unter ihrem Einfluss steht, ist aufgerufen, dem verborgenen Prozess zu vertrauen, dem Drang zu widerstehen, alles zu enthüllen oder zu überstürzen, und der Zeit ihr reifendes Werk zu überlassen. Im Verborgenen gesammelte Kraft wird zu Kraft, die Bestand hat. Ob Kind, Plan, Talent oder Beziehung — was jetzt getragen wird, tritt zu seiner rechten Stunde hervor, gestärkt durch die Geborgenheit, in der es wuchs.'),

-- ── Menzil 3 — Ülker Yıldızı / Süreyya ──────────────────────
('b1000000-0000-4000-8000-000000000003', 3, 'en', 'The Pleiades',
 'The station of abundance, protection and spiritual support.',
 'The Pleiades cluster, in popular belief, is the station that shields against the evil eye and opens the door to good fortune. For those upon whom it falls, the flow of material and spiritual abundance comes easily; the protection of loved ones is felt watching over them. This is a station of grace, where blessings seem to arrive without struggle and where unseen support surrounds every step. Those attuned to it often notice small mercies gathering around them — a timely help, an unexpected kindness, a sense of being held. It is a favourable season to receive as well as to give, to acknowledge the care of family and community, and to trust that one is not walking alone. The Pleiades remind us that prosperity is not only earned but also granted, and that gratitude keeps its channels open. Under this influence, generosity returns multiplied, and the heart that gives thanks finds its store replenished. It is a time to feel protected, to lean into support, and to let abundance circulate freely.'),
('b2000000-0000-4000-8000-000000000003', 3, 'de', 'Das Siebengestirn',
 'Die Station der Fülle, des Schutzes und der geistigen Unterstützung.',
 'Das Siebengestirn (die Plejaden) gilt im Volksglauben als jene Station, die vor dem bösen Blick schützt und dem Glück die Tür öffnet. Für jene, auf die es fällt, fließt der materielle wie geistige Reichtum mühelos; der Schutz der Geliebten wird über ihnen spürbar. Dies ist eine Station der Gnade, in der Segnungen ohne Mühe einzutreffen scheinen und unsichtbare Unterstützung jeden Schritt umgibt. Wer auf sie eingestimmt ist, bemerkt oft kleine Wohltaten um sich her — eine rechtzeitige Hilfe, eine unerwartete Freundlichkeit, das Gefühl, getragen zu sein. Es ist eine günstige Zeit, ebenso zu empfangen wie zu geben, die Fürsorge von Familie und Gemeinschaft anzuerkennen und darauf zu vertrauen, dass man nicht allein geht. Das Siebengestirn erinnert daran, dass Wohlstand nicht nur verdient, sondern auch geschenkt wird und dass Dankbarkeit seine Kanäle offen hält. Unter diesem Einfluss kehrt Großzügigkeit vervielfacht zurück, und das dankbare Herz findet seinen Vorrat erneuert.'),

-- ── Menzil 4 — Boğa Gözü / Debaran ──────────────────────────
('b1000000-0000-4000-8000-000000000004', 4, 'en', 'The Bull''s Eye',
 'The station of perseverance, stability and tangible success.',
 'The star Aldebaran lies at the centre of this station; in the classical tradition it is associated with the theme of "seeing what is real." Those upon whom this station falls are steadfast, persevering and successful over the long term. This is not the fortune of the sudden leap but of the patient stride — success built brick by brick, resting on discipline and endurance rather than luck. Under its influence, illusions fall away and one is called to look clearly at things as they truly are, to build upon fact rather than fantasy. The Bull''s Eye rewards those who commit and stay, who honour their word and their work, and who understand that lasting achievement is the child of consistency. Nothing gained here is fragile; what is won is won to keep. It is a favourable time to lay foundations, to invest in what endures, and to trust the slow accumulation of effort. Those attuned to this station find that steadiness itself becomes a kind of power, and that the ground beneath their feet grows firmer with each faithful step.'),
('b2000000-0000-4000-8000-000000000004', 4, 'de', 'Das Stierauge',
 'Die Station der Beharrlichkeit, Stabilität und des greifbaren Erfolgs.',
 'Der Stern Aldebaran liegt im Zentrum dieser Station; in der klassischen Überlieferung wird sie mit dem Thema verbunden, „das Wirkliche zu sehen“. Jene, auf die diese Station fällt, sind standhaft, beharrlich und langfristig erfolgreich. Dies ist nicht das Glück des plötzlichen Sprungs, sondern des geduldigen Schritts — Erfolg, Ziegel um Ziegel errichtet, gegründet auf Disziplin und Ausdauer statt auf Zufall. Unter ihrem Einfluss fallen Illusionen ab, und man ist aufgerufen, die Dinge klar zu sehen, wie sie wirklich sind, und auf Tatsachen statt auf Wunschbilder zu bauen. Das Stierauge belohnt jene, die sich binden und bleiben, die ihr Wort und ihre Arbeit ehren und die begreifen, dass dauerhafte Errungenschaft das Kind der Beständigkeit ist. Nichts, was hier gewonnen wird, ist zerbrechlich; was errungen wird, wird für die Dauer errungen. Es ist eine günstige Zeit, Fundamente zu legen und in das Beständige zu investieren. Wer auf diese Station eingestimmt ist, erfährt, dass die Stetigkeit selbst zu einer Art Kraft wird.'),

-- ── Menzil 5 — Üç Yıldız / Hekaa ────────────────────────────
('b1000000-0000-4000-8000-000000000005', 5, 'en', 'The Three Stars',
 'The station of movement, travel and new horizons.',
 'This station is associated with the theme of travel, relocation and physical change of place. For those upon whom it falls, setting out on the road and discovering a new city or country is favourable. It carries the restless, expansive energy of the horizon — a pull toward the unfamiliar and a readiness to leave the known behind. Under its influence, staying still can feel confining, while movement brings clarity and renewal. This is a time to say yes to the journey, whether outward across distance or inward toward a fresh way of living. New landscapes reshape the mind; new places awaken what has grown dull in the old. The Three Stars remind us that some things can only be learned by going, that the road itself teaches, and that a change of scenery is often a change of soul. Those attuned to this station should trust the impulse to explore, to break routine, and to let the wider world in. What awaits beyond the next threshold may be exactly what the spirit has been longing for.'),
('b2000000-0000-4000-8000-000000000005', 5, 'de', 'Die drei Sterne',
 'Die Station der Bewegung, der Reise und neuer Horizonte.',
 'Diese Station wird mit dem Thema Reise, Umzug und körperlichem Ortswechsel verbunden. Für jene, auf die sie fällt, ist es günstig, sich auf den Weg zu machen und eine neue Stadt oder ein neues Land kennenzulernen. Sie trägt die rastlose, weite Energie des Horizonts in sich — einen Sog zum Unbekannten und die Bereitschaft, das Vertraute hinter sich zu lassen. Unter ihrem Einfluss kann Stillstand beengend wirken, während Bewegung Klarheit und Erneuerung bringt. Dies ist eine Zeit, Ja zur Reise zu sagen, sei es äußerlich über die Ferne oder innerlich hin zu einer neuen Art zu leben. Neue Landschaften formen den Geist um; neue Orte erwecken, was im Alten stumpf geworden ist. Die drei Sterne erinnern daran, dass manches nur durch das Gehen gelernt werden kann, dass der Weg selbst lehrt und dass ein Ortswechsel oft ein Wandel der Seele ist. Wer auf diese Station eingestimmt ist, sollte dem Drang zum Entdecken vertrauen und die weite Welt hereinlassen.'),

-- ── Menzil 6 — İkizler Eli / Hena ───────────────────────────
('b1000000-0000-4000-8000-000000000006', 6, 'en', 'The Twins'' Hand',
 'The station of communication, connection and new acquaintances.',
 'This is a station where social relationships, new friendships and important communications intensify. It is a favourable time for agreements, contracts and negotiations. The energy here flows through words and links between people — the exchange of ideas, the meeting of minds, the building of bridges. Under its influence, doors open through conversation; what is spoken clearly and heard well can shape the course of events. This is a moment to reach out, to introduce yourself, to say what needs saying and to listen closely in return. New acquaintances made now may prove significant; alliances formed here have the potential to last. The Twins'' Hand rewards openness, curiosity and the willingness to connect. It reminds us that we do not move through life alone, and that the right word at the right moment can change everything. Those attuned to this station should attend to their correspondence, honour their promises, and treat every conversation as a possible turning point. Clarity of expression and generosity of attention are the currencies that prosper here.'),
('b2000000-0000-4000-8000-000000000006', 6, 'de', 'Die Hand der Zwillinge',
 'Die Station der Kommunikation, der Verbindung und neuer Bekanntschaften.',
 'Dies ist eine Station, in der sich soziale Beziehungen, neue Freundschaften und wichtige Gespräche verdichten. Es ist eine günstige Zeit für Vereinbarungen, Verträge und Verhandlungen. Die Energie fließt hier durch Worte und die Bande zwischen Menschen — den Austausch von Gedanken, das Zusammentreffen der Köpfe, den Bau von Brücken. Unter ihrem Einfluss öffnen sich Türen durch das Gespräch; was klar gesagt und gut gehört wird, kann den Lauf der Dinge formen. Dies ist ein Moment, auf andere zuzugehen, sich vorzustellen, das Nötige auszusprechen und im Gegenzug aufmerksam zuzuhören. Jetzt geknüpfte Bekanntschaften können bedeutsam werden; hier geschlossene Bündnisse haben das Potenzial zu bestehen. Die Hand der Zwillinge belohnt Offenheit, Neugier und die Bereitschaft, sich zu verbinden. Sie erinnert daran, dass wir nicht allein durchs Leben gehen und dass das rechte Wort im rechten Augenblick alles verändern kann. Wer auf diese Station eingestimmt ist, sollte seine Versprechen ehren und jedes Gespräch als möglichen Wendepunkt behandeln.'),

-- ── Menzil 7 — Aslan Pençesi / Zira ─────────────────────────
('b1000000-0000-4000-8000-000000000007', 7, 'en', 'The Lion''s Paw',
 'The station of visible power, authority and leadership.',
 'For those upon whom this station falls, recognition, appreciation and opportunities for leadership are near. It is favourable to stand at the very centre of the stage. This is a station of visible strength — a time when one''s presence is felt, one''s voice carries, and the world turns its attention toward you. Under its influence, hiding one''s light serves no one; the moment calls for stepping forward and claiming the role that fits. Authority here is not domination but the natural gravity of someone who knows their worth and acts from it. The Lion''s Paw rewards confidence tempered by dignity, and leadership rooted in genuine capability rather than mere ambition. It is a time to accept responsibility, to let yourself be seen, and to lead where leadership is needed. Those attuned to this station find that others look to them for direction, and that carrying such trust well brings both honour and growth. To shine now is not vanity but service — the offering of one''s strength for a purpose larger than oneself.'),
('b2000000-0000-4000-8000-000000000007', 7, 'de', 'Die Löwentatze',
 'Die Station der sichtbaren Macht, der Autorität und der Führung.',
 'Für jene, auf die diese Station fällt, sind Anerkennung, Wertschätzung und Gelegenheiten zur Führung nahe. Es ist günstig, in der Mitte der Bühne zu stehen. Dies ist eine Station der sichtbaren Stärke — eine Zeit, in der die eigene Gegenwart spürbar ist, die Stimme trägt und die Welt ihre Aufmerksamkeit auf einen richtet. Unter ihrem Einfluss dient es niemandem, das eigene Licht zu verbergen; der Augenblick verlangt danach, vorzutreten und die passende Rolle einzunehmen. Autorität ist hier keine Beherrschung, sondern die natürliche Anziehung eines Menschen, der seinen Wert kennt und aus ihm heraus handelt. Die Löwentatze belohnt Selbstvertrauen, gemildert durch Würde, und Führung, die in echter Fähigkeit statt in bloßem Ehrgeiz wurzelt. Es ist eine Zeit, Verantwortung anzunehmen, sich zeigen zu lassen und dort zu führen, wo Führung gebraucht wird. Wer auf diese Station eingestimmt ist, erfährt, dass andere zu ihm um Richtung aufschauen und dass es Ehre wie Wachstum bringt, dieses Vertrauen gut zu tragen.'),

-- ── Menzil 8 — Kartal / Nesre ───────────────────────────────
('b1000000-0000-4000-8000-000000000008', 8, 'en', 'The Eagle',
 'The station of ascent, wide vision and foresight.',
 'This is the ideal station for stepping back and seeing the whole picture. It is a time for strategic decisions, long-term plans and personal ascent. Like the eagle rising above the landscape, one is granted a higher vantage from which patterns become clear and the path ahead reveals itself. Under its influence, the small anxieties of the moment shrink to their proper size, and the mind is freed to think in terms of years rather than days. This is not a season for getting lost in detail but for lifting the gaze, weighing directions, and choosing the course that serves the larger arc of a life. The Eagle rewards those who plan with breadth and act with foresight, who understand that where one is going matters more than how fast one is moving. It is a favourable time to set ambitious goals, to align daily effort with a distant destination, and to trust the clarity that comes with height. Those attuned to this station find that perspective itself is power, and that the one who sees furthest travels surest.'),
('b2000000-0000-4000-8000-000000000008', 8, 'de', 'Der Adler',
 'Die Station des Aufstiegs, des weiten Blicks und der Weitsicht.',
 'Dies ist die ideale Station, um einen Schritt zurückzutreten und das ganze Bild zu sehen. Es ist eine Zeit für strategische Entscheidungen, langfristige Pläne und persönlichen Aufstieg. Wie der Adler, der sich über die Landschaft erhebt, wird einem eine höhere Warte geschenkt, von der aus Muster klar werden und sich der Weg nach vorn offenbart. Unter ihrem Einfluss schrumpfen die kleinen Sorgen des Augenblicks auf ihr rechtes Maß, und der Geist wird frei, in Jahren statt in Tagen zu denken. Dies ist keine Zeit, sich im Detail zu verlieren, sondern den Blick zu heben, Richtungen abzuwägen und den Kurs zu wählen, der dem größeren Bogen eines Lebens dient. Der Adler belohnt jene, die weiträumig planen und mit Weitsicht handeln, die begreifen, dass das Wohin wichtiger ist als das Wie schnell. Es ist eine günstige Zeit, ehrgeizige Ziele zu setzen und die tägliche Mühe mit einem fernen Ziel in Einklang zu bringen. Wer auf diese Station eingestimmt ist, erfährt, dass die Übersicht selbst Macht ist.'),

-- ── Menzil 9 — Bakış / Tarf ─────────────────────────────────
('b1000000-0000-4000-8000-000000000009', 9, 'en', 'The Gaze',
 'The station of clear sight and recognising the truth.',
 'This is a period in which illusions dissolve and the truth appears more clearly. Whatever has been wearing a mask in one''s relationships is now seen for what it is; this is a difficult but liberating station. Under its influence, the comforting fictions we have told ourselves lose their power, and reality — however unwelcome — comes into focus. It can be a testing time, for what is revealed cannot easily be unseen. Yet there is freedom in this clarity: to know the truth is to be released from the exhausting work of pretending. The Gaze asks for the courage to look, to name what is real, and to act on what one now understands. Relationships may be redefined, false hopes released, and genuine bonds distinguished from convenient ones. Those attuned to this station should trust their perception, honour the discomfort of insight, and remember that sight, once granted, is a gift even when it wounds. What is seen truly can finally be dealt with truly. Clarity is the beginning of every honest new step.'),
('b2000000-0000-4000-8000-000000000009', 9, 'de', 'Der Blick',
 'Die Station des klaren Sehens und des Erkennens der Wahrheit.',
 'Dies ist eine Zeit, in der Illusionen sich auflösen und die Wahrheit klarer hervortritt. Was in den eigenen Beziehungen eine Maske getragen hat, wird nun als das erkannt, was es ist; dies ist eine schwierige, aber befreiende Station. Unter ihrem Einfluss verlieren die tröstlichen Geschichten, die wir uns erzählt haben, ihre Kraft, und die Wirklichkeit — so unwillkommen sie sein mag — tritt in den Fokus. Es kann eine prüfende Zeit sein, denn was offenbart wird, lässt sich nicht leicht wieder übersehen. Doch in dieser Klarheit liegt Freiheit: die Wahrheit zu kennen heißt, von der erschöpfenden Arbeit des Vortäuschens erlöst zu sein. Der Blick verlangt den Mut hinzuschauen, das Wirkliche zu benennen und nach dem zu handeln, was man nun versteht. Beziehungen mögen neu bestimmt, falsche Hoffnungen losgelassen und echte Bindungen von bequemen unterschieden werden. Wer auf diese Station eingestimmt ist, sollte seiner Wahrnehmung vertrauen und daran denken, dass Sicht, einmal geschenkt, ein Geschenk ist, selbst wenn sie verwundet.'),

-- ── Menzil 10 — Alın / Cebhe ────────────────────────────────
('b1000000-0000-4000-8000-000000000010', 10, 'en', 'The Forehead',
 'The station of will, resolve and directness.',
 'Cebhe means "the forehead" — this is a time for making an important decision, acting directly and stating your intention plainly. It is not a time for postponement. The forehead is where resolve gathers before action, and this station carries the concentrated force of will meeting the world head-on. Under its influence, ambiguity becomes a burden and half-measures satisfy no one; what is called for is clarity of purpose and the courage to declare it. This is a moment to choose a path and commit to it, to stop circling the matter and step straight into it. The Forehead rewards those who are direct without being harsh, decisive without being reckless, and honest about what they want. Delay now only breeds doubt; forward motion dissolves it. Those attuned to this station should trust that a clearly stated intention has power, that others respond to firmness of purpose, and that the decision made cleanly today spares much confusion tomorrow. Stand behind your choice, speak it aloud, and let your resolve carry you through.'),
('b2000000-0000-4000-8000-000000000010', 10, 'de', 'Die Stirn',
 'Die Station des Willens, der Entschlossenheit und der Direktheit.',
 'Cebhe bedeutet „die Stirn“ — dies ist eine Zeit, eine wichtige Entscheidung zu treffen, direkt zu handeln und die eigene Absicht klar auszusprechen. Es ist keine Zeit des Aufschiebens. Die Stirn ist der Ort, an dem sich Entschlossenheit vor der Tat sammelt, und diese Station trägt die gebündelte Kraft des Willens, der der Welt geradewegs begegnet. Unter ihrem Einfluss wird Mehrdeutigkeit zur Last, und Halbheiten befriedigen niemanden; gefragt ist Klarheit der Absicht und der Mut, sie zu erklären. Dies ist ein Moment, einen Weg zu wählen und sich ihm zu verpflichten, das Thema nicht länger zu umkreisen, sondern geradewegs hineinzutreten. Die Stirn belohnt jene, die direkt sind, ohne schroff zu sein, entschieden, ohne leichtsinnig zu sein, und ehrlich über ihre Wünsche. Zögern nährt jetzt nur den Zweifel; Vorwärtsbewegung löst ihn auf. Wer auf diese Station eingestimmt ist, sollte darauf vertrauen, dass eine klar ausgesprochene Absicht Macht besitzt und dass die heute sauber getroffene Entscheidung morgen viel Verwirrung erspart.'),

-- ── Menzil 11 — Sırt / Zübra ────────────────────────────────
('b1000000-0000-4000-8000-000000000011', 11, 'en', 'The Back',
 'The station of bearing burdens, responsibility and endurance.',
 'This station is associated with the theme of endurance and the taking on of responsibility. Even if you are passing through a demanding period, the strength to carry it is within you. The Back is that which bears weight, and this station speaks to the quiet dignity of shouldering what must be shouldered. Under its influence, life may ask more of you than usual — obligations to family, duties that cannot be set down, a load that tests your resilience. Yet the very presence of this station is a reminder that the burden and the capacity to bear it arrive together. This is a time to steady yourself, to accept what is yours to carry, and to draw on reserves of endurance you may not have known you possessed. The Back rewards patience under pressure and faithfulness to one''s responsibilities. Those attuned to it discover that strength is not the absence of weight but the ability to walk on beneath it. What is carried well now becomes the source of a deeper, tested confidence that no easy season could have granted.'),
('b2000000-0000-4000-8000-000000000011', 11, 'de', 'Der Rücken',
 'Die Station des Lastentragens, der Verantwortung und der Ausdauer.',
 'Diese Station wird mit dem Thema Ausdauer und der Übernahme von Verantwortung verbunden. Selbst wenn du eine fordernde Zeit durchlebst — die Kraft, sie zu tragen, liegt in dir. Der Rücken ist das, was Gewicht trägt, und diese Station spricht von der stillen Würde, das zu schultern, was geschultert werden muss. Unter ihrem Einfluss mag das Leben mehr von dir verlangen als sonst — Verpflichtungen gegenüber der Familie, Pflichten, die nicht abgelegt werden können, eine Last, die deine Widerstandskraft prüft. Doch schon die Gegenwart dieser Station ist eine Erinnerung daran, dass die Last und die Fähigkeit, sie zu tragen, gemeinsam eintreffen. Dies ist eine Zeit, dich zu festigen, anzunehmen, was zu tragen dir zusteht, und aus Reserven der Ausdauer zu schöpfen, von denen du vielleicht nichts wusstest. Der Rücken belohnt Geduld unter Druck und Treue zu den eigenen Pflichten. Wer auf ihn eingestimmt ist, entdeckt, dass Stärke nicht das Fehlen von Gewicht ist, sondern die Fähigkeit, darunter weiterzugehen.'),

-- ── Menzil 12 — Çevrilme / Sarfe ────────────────────────────
('b1000000-0000-4000-8000-000000000012', 12, 'en', 'The Turning',
 'The station of transformation and parting from the old.',
 'This is the threshold where one cycle completes and another begins. It is a favourable time for parting from old habits, relationships or occupations; room is made for the new. The Turning names that pivotal moment when what has run its course must be released so that what is coming can enter. Under its influence, holding on grows costly and letting go grows wise. It can feel like loss, yet it is truly transition — the necessary emptying that precedes every genuine renewal. This is a time to review what no longer serves, to close doors with gratitude rather than regret, and to trust that endings are the soil of beginnings. The Turning rewards those willing to change, to shed the outworn skin, and to walk forward without dragging the whole past behind them. Those attuned to this station should not cling to what is departing; instead they should bless it and turn toward the fresh horizon. What you make space for now is what your future will be built upon. Change here is not disruption but liberation.'),
('b2000000-0000-4000-8000-000000000012', 12, 'de', 'Die Wende',
 'Die Station der Verwandlung und des Abschieds vom Alten.',
 'Dies ist die Schwelle, an der ein Zyklus sich vollendet und ein anderer beginnt. Es ist eine günstige Zeit, sich von alten Gewohnheiten, Beziehungen oder Beschäftigungen zu trennen; Raum für das Neue wird geschaffen. Die Wende bezeichnet jenen entscheidenden Augenblick, in dem das Abgelaufene losgelassen werden muss, damit das Kommende eintreten kann. Unter ihrem Einfluss wird Festhalten kostspielig und Loslassen weise. Es mag sich wie Verlust anfühlen, doch in Wahrheit ist es Übergang — die notwendige Leerung, die jeder echten Erneuerung vorausgeht. Dies ist eine Zeit, zu prüfen, was nicht mehr dient, Türen mit Dankbarkeit statt mit Bedauern zu schließen und darauf zu vertrauen, dass Enden der Boden der Anfänge sind. Die Wende belohnt jene, die bereit sind, sich zu wandeln, die abgetragene Haut abzustreifen und vorwärtszugehen, ohne die ganze Vergangenheit hinter sich herzuziehen. Wer auf diese Station eingestimmt ist, sollte nicht am Scheidenden hängen, sondern es segnen und sich dem frischen Horizont zuwenden.'),

-- ── Menzil 13 — Havlama / Avva ──────────────────────────────
('b1000000-0000-4000-8000-000000000013', 13, 'en', 'The Barking',
 'The station of speaking out, expression and creativity.',
 'This is the ideal station for saying what has gone unsaid and expressing what has been held within. It is favourable for creative projects, writing, music and art. The Barking names the impulse to make oneself heard — to break the silence that has grown heavy and to let the inner voice find its outward form. Under its influence, suppression becomes uncomfortable and expression becomes healing; feelings and ideas that have been bottled up press toward release. This is a time to create without over-editing, to speak your truth, and to trust that your voice deserves to reach the air. The Barking rewards boldness of expression and the courage to be authentic rather than agreeable. Whether through conversation long postponed or through a work of art taking shape, what you release now clears an inner pressure and opens a channel of vitality. Those attuned to this station should give form to what stirs within — write it, sing it, paint it, say it. To express is to become more fully yourself, and what is voiced honestly carries a power that silence never could.'),
('b2000000-0000-4000-8000-000000000013', 13, 'de', 'Das Bellen',
 'Die Station des Sich-Äußerns, des Ausdrucks und der Kreativität.',
 'Dies ist die ideale Station, um das Ungesagte auszusprechen und das im Inneren Gehaltene auszudrücken. Sie ist günstig für kreative Vorhaben, für das Schreiben, die Musik und die Kunst. Das Bellen bezeichnet den Drang, sich Gehör zu verschaffen — das schwer gewordene Schweigen zu brechen und der inneren Stimme ihre äußere Form finden zu lassen. Unter ihrem Einfluss wird Unterdrückung unbehaglich und Ausdruck heilsam; Gefühle und Gedanken, die aufgestaut wurden, drängen zur Freisetzung. Dies ist eine Zeit, zu erschaffen, ohne sich zu sehr zu zensieren, die eigene Wahrheit auszusprechen und darauf zu vertrauen, dass die eigene Stimme es verdient, gehört zu werden. Das Bellen belohnt die Kühnheit des Ausdrucks und den Mut, echt statt gefällig zu sein. Ob durch ein lange aufgeschobenes Gespräch oder durch ein entstehendes Kunstwerk — was du jetzt freisetzt, löst einen inneren Druck und öffnet einen Kanal der Lebenskraft. Wer auf diese Station eingestimmt ist, sollte dem, was sich innen regt, Gestalt geben.'),

-- ── Menzil 14 — Yüksek / Simak ──────────────────────────────
('b1000000-0000-4000-8000-000000000014', 14, 'en', 'The Lofty',
 'The station of the summit, nearing success and surrender.',
 'This is the station where long efforts bear fruit. Yet surrender at the summit matters — it is important not to fall into arrogance and to preserve humility. The Lofty marks the arrival at a peak long climbed toward, the moment when reward comes into reach. Under its influence, achievement is near, but so is the subtle danger that success brings: the temptation to grow proud, to forget the labour and the help that carried one here. The true completion of this station is not merely reaching the top but reaching it gracefully. This is a time to receive one''s due with gratitude, to honour those who assisted the climb, and to hold accomplishment lightly. The Lofty rewards those who succeed without losing themselves, who stay grounded even as they rise. Those attuned to it understand that the highest achievement is inseparable from humility, and that the summit is best enjoyed by one who remembers the valley. Take the victory, but keep the open heart. What is won with grace endures; what is won with pride invites its own fall.'),
('b2000000-0000-4000-8000-000000000014', 14, 'de', 'Der Erhabene',
 'Die Station des Gipfels, der nahenden Erfüllung und der Hingabe.',
 'Dies ist die Station, in der lange Mühen Frucht tragen. Doch die Hingabe auf dem Gipfel ist entscheidend — es ist wichtig, nicht in Überheblichkeit zu verfallen und die Demut zu bewahren. Der Erhabene bezeichnet das Erreichen eines lange erstrebten Gipfels, den Augenblick, in dem der Lohn in Reichweite kommt. Unter seinem Einfluss ist die Errungenschaft nahe, doch ebenso die feine Gefahr, die der Erfolg mit sich bringt: die Versuchung, stolz zu werden, die Mühe und die Hilfe zu vergessen, die einen hierher getragen haben. Die wahre Vollendung dieser Station besteht nicht bloß darin, den Gipfel zu erreichen, sondern ihn mit Anmut zu erreichen. Dies ist eine Zeit, das Verdiente mit Dankbarkeit anzunehmen, jene zu ehren, die beim Aufstieg halfen, und die Errungenschaft leicht zu halten. Der Erhabene belohnt jene, die Erfolg haben, ohne sich selbst zu verlieren. Wer auf ihn eingestimmt ist, versteht, dass die höchste Errungenschaft von der Demut untrennbar ist und der Gipfel dem am besten schmeckt, der das Tal nicht vergisst.'),

-- ── Menzil 15 — Örtü / Gafr ─────────────────────────────────
('b1000000-0000-4000-8000-000000000015', 15, 'en', 'The Veil',
 'The station of refuge, withdrawal and rest.',
 'This station symbolises a temporary refuge. If fatigue has accumulated, it is time to take a pause; it is favourable for inner recovery. The Veil draws a soft curtain around one, offering shelter from the demands of the outer world. Under its influence, retreat is not weakness but wisdom — the body and spirit ask to be replenished, and honouring that request is itself an act of strength. This is a time to step back from the noise, to rest without guilt, and to tend to what has been depleted. Beneath the veil, healing quietly does its work; what is hidden and protected can mend. The Veil rewards those who know when to stop, who understand that stillness restores what exertion drains. Those attuned to this station should give themselves permission to withdraw, to sleep, to be quiet, and to let the fields of the self lie fallow for a season. Not every moment is for advancing; some are for gathering strength in the shade. Emerge only when truly rested. The refuge you accept now becomes the vigour you carry forward.'),
('b2000000-0000-4000-8000-000000000015', 15, 'de', 'Der Schleier',
 'Die Station der Zuflucht, des Rückzugs und der Ruhe.',
 'Diese Station versinnbildlicht eine vorübergehende Zuflucht. Hat sich Müdigkeit angesammelt, so ist es Zeit für eine Pause; sie ist günstig für die innere Erholung. Der Schleier zieht einen sanften Vorhang um einen und bietet Schutz vor den Forderungen der äußeren Welt. Unter seinem Einfluss ist Rückzug keine Schwäche, sondern Weisheit — Körper und Geist verlangen danach, aufgefüllt zu werden, und dieser Bitte nachzukommen ist selbst ein Akt der Stärke. Dies ist eine Zeit, vom Lärm zurückzutreten, ohne Schuldgefühl zu ruhen und dem zuzuwenden, was erschöpft ist. Unter dem Schleier verrichtet die Heilung still ihr Werk; was verborgen und geschützt ist, kann genesen. Der Schleier belohnt jene, die wissen, wann sie innehalten müssen, und die begreifen, dass Stille wiederherstellt, was Anstrengung leert. Wer auf diese Station eingestimmt ist, sollte sich erlauben, sich zurückzuziehen, zu schlafen und still zu sein. Nicht jeder Augenblick ist zum Vorankommen; manche sind dazu da, im Schatten Kraft zu sammeln.'),

-- ── Menzil 16 — Terazi Kefesi / Zubana ──────────────────────
('b1000000-0000-4000-8000-000000000016', 16, 'en', 'The Scale''s Pan',
 'The station of seeking balance, justice and relationship.',
 'This station is favourable for finding the middle way between two extremes, for being fair and for establishing balance in a relationship. Composure is important when making decisions. The Scale''s Pan speaks to the delicate art of weighing — of holding opposing claims in even measure and refusing to be swept fully to either side. Under its influence, harmony is achieved not by ignoring tension but by honouring both sides of it, giving each its due. This is a time to mediate rather than to dominate, to listen before judging, and to seek the equitable resolution that leaves no party unheard. In relationships, it calls for balance between giving and receiving, speaking and listening, self and other. The Scale''s Pan rewards fairness, patience and the cool head that resists reacting in the heat of the moment. Those attuned to this station should weigh their choices carefully, treat others justly, and trust that a fair outcome, reached calmly, is stronger than a swift one reached in anger. Equilibrium here is not passivity but the active, ongoing work of keeping the scales true.'),
('b2000000-0000-4000-8000-000000000016', 16, 'de', 'Die Waagschale',
 'Die Station des Suchens nach Gleichgewicht, Gerechtigkeit und Beziehung.',
 'Diese Station ist günstig, um den Mittelweg zwischen zwei Extremen zu finden, gerecht zu sein und in einer Beziehung Gleichgewicht herzustellen. Gelassenheit ist beim Treffen von Entscheidungen wichtig. Die Waagschale spricht von der feinen Kunst des Abwägens — gegensätzliche Ansprüche in gleichem Maße zu halten und sich nicht ganz auf eine Seite ziehen zu lassen. Unter ihrem Einfluss wird Harmonie nicht durch das Ignorieren von Spannung erreicht, sondern indem man beide Seiten ehrt und jeder das Ihre gibt. Dies ist eine Zeit, zu vermitteln statt zu beherrschen, zuzuhören, bevor man urteilt, und die gerechte Lösung zu suchen, die keine Partei ungehört lässt. In Beziehungen verlangt sie das Gleichgewicht zwischen Geben und Nehmen, Sprechen und Zuhören, Selbst und Anderem. Die Waagschale belohnt Fairness, Geduld und den kühlen Kopf, der sich weigert, in der Hitze des Augenblicks zu reagieren. Wer auf diese Station eingestimmt ist, sollte seine Entscheidungen sorgfältig abwägen und darauf vertrauen, dass ein ruhig erreichtes, gerechtes Ergebnis stärker ist als ein rasches im Zorn.'),

-- ── Menzil 17 — Taç / İklil ─────────────────────────────────
('b1000000-0000-4000-8000-000000000017', 17, 'en', 'The Crown',
 'The station of honour, appreciation and status.',
 'This station is one where signs of appreciation — social acceptance, reward, promotion — are near. It is a good time to renew your self-respect. The Crown marks a moment of recognition, when the world affirms one''s worth and one''s standing rises. Under its influence, the labour of past seasons is acknowledged, and honours long deserved find their way to you. Yet the deepest meaning of the Crown is not the outer accolade but the inner dignity it should reflect — the sense of self-worth that no external reward can truly grant and none can truly take away. This is a time to accept recognition graciously, to let yourself be honoured, and above all to honour yourself. The Crown rewards those who value their own worth without arrogance, who carry status with grace, and who let outer acknowledgement deepen rather than inflate them. Those attuned to this station should receive their due, celebrate their progress, and renew their relationship with their own dignity. A crown worn well is a crown worn humbly — the true measure of status is how lightly one carries it.'),
('b2000000-0000-4000-8000-000000000017', 17, 'de', 'Die Krone',
 'Die Station der Ehrung, der Anerkennung und des Status.',
 'Diese Station ist eine, in der Zeichen der Anerkennung — gesellschaftliche Annahme, Belohnung, Beförderung — nahe sind. Es ist eine gute Zeit, die eigene Selbstachtung zu erneuern. Die Krone bezeichnet einen Augenblick der Anerkennung, in dem die Welt den eigenen Wert bestätigt und das eigene Ansehen steigt. Unter ihrem Einfluss wird die Mühe vergangener Zeiten gewürdigt, und lange verdiente Ehren finden ihren Weg zu einem. Doch die tiefste Bedeutung der Krone ist nicht die äußere Auszeichnung, sondern die innere Würde, die sie widerspiegeln sollte — jenes Gefühl des Selbstwerts, das keine äußere Belohnung wahrhaft schenken und keine wahrhaft nehmen kann. Dies ist eine Zeit, Anerkennung anmutig anzunehmen, sich ehren zu lassen und vor allem sich selbst zu ehren. Die Krone belohnt jene, die ihren eigenen Wert ohne Überheblichkeit schätzen und den Status mit Anmut tragen. Wer auf diese Station eingestimmt ist, sollte das Verdiente empfangen und die Beziehung zur eigenen Würde erneuern. Eine gut getragene Krone ist eine demütig getragene.'),

-- ── Menzil 18 — Akrep Kalbi / Kalb ──────────────────────────
('b1000000-0000-4000-8000-000000000018', 18, 'en', 'The Scorpion''s Heart',
 'The station of intense feeling, deep bonds and transformative relationship.',
 'The star Antares lies at the centre of this station. It is a time for intense emotional moments, deep bonds or transformative experiences in relationship. Remaining on the surface is difficult here. The Scorpion''s Heart burns with a fierce, unguarded intimacy — the kind of encounter that reaches past politeness into the depths where real change occurs. Under its influence, feelings run strong and connections cut deep; what is touched here is touched to the core. This is a time to allow yourself to be affected, to enter relationship fully rather than cautiously, and to let love and passion do their transforming work. Such depth carries risk, for what moves us profoundly can also wound, yet it is precisely this intensity that forges the bonds worth having. The Scorpion''s Heart rewards emotional honesty and the courage to be vulnerable. Those attuned to this station should not flee from feeling but move through it, trusting that the fire refines. What is experienced in these depths leaves one changed — and often more truly alive. To love deeply now is to be transformed by the loving.'),
('b2000000-0000-4000-8000-000000000018', 18, 'de', 'Das Skorpionherz',
 'Die Station des intensiven Gefühls, tiefer Bindungen und verwandelnder Beziehung.',
 'Der Stern Antares liegt im Zentrum dieser Station. Es ist eine Zeit für intensive emotionale Augenblicke, tiefe Bindungen oder verwandelnde Erfahrungen in der Beziehung. An der Oberfläche zu bleiben ist hier schwer. Das Skorpionherz brennt mit einer heftigen, ungeschützten Innigkeit — jener Art von Begegnung, die über die Höflichkeit hinaus in jene Tiefen reicht, in denen wahrer Wandel geschieht. Unter seinem Einfluss laufen Gefühle stark und Verbindungen schneiden tief; was hier berührt wird, wird bis ins Innerste berührt. Dies ist eine Zeit, sich berühren zu lassen, ganz statt zögerlich in die Beziehung einzutreten und Liebe und Leidenschaft ihr verwandelndes Werk tun zu lassen. Solche Tiefe birgt Risiko, denn was uns zutiefst bewegt, kann auch verwunden, doch gerade diese Intensität schmiedet die Bindungen, die es wert sind. Das Skorpionherz belohnt emotionale Ehrlichkeit und den Mut, verletzlich zu sein. Wer auf diese Station eingestimmt ist, sollte nicht vor dem Gefühl fliehen, sondern es durchschreiten und darauf vertrauen, dass das Feuer läutert.'),

-- ── Menzil 19 — Akrep İğnesi / Şevle ────────────────────────
('b1000000-0000-4000-8000-000000000019', 19, 'en', 'The Scorpion''s Sting',
 'The station of sharp truth, warning and vigilance.',
 'This station symbolises a warning — there is a lack of attention in some matter, or a truth being ignored. It is time to face it. The Scorpion''s Sting delivers a sharp reminder, the small pain that alerts us to what we have been overlooking. Under its influence, complacency becomes dangerous; something requires your notice, and the longer it is avoided, the sharper the eventual reckoning. This is not a season for denial but for clear-eyed attention. A situation may be sending signals you have preferred not to read, a truth in your health, your work or your relationships that quietly asks to be acknowledged. The sting is not punishment but protection — a prompt to correct course before a small problem becomes a large one. The Scorpion''s Sting rewards vigilance, honesty and the willingness to confront what is uncomfortable. Those attuned to this station should heed the warning, examine what they have been avoiding, and act while action is still easy. To face the sharp truth now is to spare yourself a deeper wound later. Awareness, however unwelcome, is the beginning of remedy.'),
('b2000000-0000-4000-8000-000000000019', 19, 'de', 'Der Skorpionstachel',
 'Die Station der scharfen Wahrheit, der Warnung und der Wachsamkeit.',
 'Diese Station versinnbildlicht eine Warnung — in einer Sache fehlt es an Aufmerksamkeit, oder eine Wahrheit wird übersehen. Es ist Zeit, sich ihr zu stellen. Der Skorpionstachel liefert eine scharfe Mahnung, jenen kleinen Schmerz, der uns auf das aufmerksam macht, was wir übersehen haben. Unter seinem Einfluss wird Sorglosigkeit gefährlich; etwas verlangt deine Beachtung, und je länger es gemieden wird, desto schärfer die schließliche Abrechnung. Dies ist keine Zeit der Verleugnung, sondern der klaräugigen Aufmerksamkeit. Eine Lage mag Signale senden, die du lieber nicht gelesen hast — eine Wahrheit in deiner Gesundheit, deiner Arbeit oder deinen Beziehungen, die still darum bittet, anerkannt zu werden. Der Stachel ist keine Strafe, sondern Schutz — ein Anstoß, den Kurs zu korrigieren, bevor aus einem kleinen Problem ein großes wird. Der Skorpionstachel belohnt Wachsamkeit, Ehrlichkeit und die Bereitschaft, sich dem Unbequemen zu stellen. Wer auf diese Station eingestimmt ist, sollte die Warnung beachten und handeln, solange das Handeln noch leichtfällt.'),

-- ── Menzil 20 — Devekuşları / Naaim ─────────────────────────
('b1000000-0000-4000-8000-000000000020', 20, 'en', 'The Ostriches',
 'The station of speed, running and the pursuit of a goal.',
 'This is an active, fast, goal-focused period. It is favourable to press ahead stubbornly along a single path; stay away from multitasking. The Ostriches run swiftly and single-mindedly toward the horizon, and this station carries that same driving momentum. Under its influence, scattered energy achieves little, but concentrated energy achieves much; the key is to choose one direction and pursue it with full commitment. This is a time for speed and focus, for narrowing your aim to the one thing that matters most and running hard toward it. Distraction is the enemy here; the temptation to chase several aims at once dilutes the very force that could carry you to any of them. The Ostriches reward decisiveness, momentum and the discipline of a fixed target. Those attuned to this station should pick their goal, silence the competing pulls, and let velocity work in their favour. Speed rewards the committed and punishes the divided. Run one race well rather than three races poorly, and the finish line will meet you sooner than you expect. Momentum, once gained, becomes its own ally.'),
('b2000000-0000-4000-8000-000000000020', 20, 'de', 'Die Strauße',
 'Die Station der Geschwindigkeit, des Laufens und des Verfolgens eines Ziels.',
 'Dies ist eine tätige, schnelle, zielgerichtete Zeit. Es ist günstig, beharrlich einem einzigen Weg zu folgen; halte dich vom Vielerlei gleichzeitig fern. Die Strauße laufen rasch und zielstrebig zum Horizont, und diese Station trägt denselben treibenden Schwung. Unter ihrem Einfluss erreicht zerstreute Energie wenig, gebündelte Energie hingegen viel; der Schlüssel liegt darin, eine Richtung zu wählen und sie mit vollem Einsatz zu verfolgen. Dies ist eine Zeit für Geschwindigkeit und Fokus, dein Ziel auf das eine Wichtigste zu verengen und beherzt darauf zuzulaufen. Ablenkung ist hier der Feind; die Versuchung, mehrere Ziele auf einmal zu jagen, verwässert gerade jene Kraft, die dich zu einem von ihnen tragen könnte. Die Strauße belohnen Entschlossenheit, Schwung und die Disziplin eines festen Ziels. Wer auf diese Station eingestimmt ist, sollte sein Ziel wählen und die widerstreitenden Zugkräfte zum Schweigen bringen. Laufe ein Rennen gut statt drei Rennen schlecht, und die Ziellinie kommt dir näher, als du erwartest.'),

-- ── Menzil 21 — Boş Yer / Belde ─────────────────────────────
('b1000000-0000-4000-8000-000000000021', 21, 'en', 'The Empty Place',
 'The station of uncertainty, the interval and expectation.',
 'This is a zone of transition where neither the old nor the new is present. Do not decide in haste; listen to your intuition and accept the moment. The Empty Place is the pause between chapters, the fertile void in which nothing yet has form. Under its influence, clarity is not available on demand; the situation is still shaping itself, and pushing for resolution too soon only distorts what is trying to emerge. This is a time to tolerate not-knowing, to resist the discomfort that drives premature decisions, and to trust that the way forward will reveal itself when the moment ripens. The Empty Place rewards patience, inner listening and the willingness to sit in openness rather than rushing to fill the space. Those attuned to this station should treat uncertainty not as failure but as a natural phase of becoming. Let the interval do its quiet work; attend to your intuition, which often speaks most clearly in the stillness of not-yet. What feels like emptiness now is space being cleared for something you cannot yet name. Wait, watch, and let the emerging shape find you.'),
('b2000000-0000-4000-8000-000000000021', 21, 'de', 'Der leere Ort',
 'Die Station der Ungewissheit, des Zwischenraums und der Erwartung.',
 'Dies ist eine Übergangszone, in der weder das Alte noch das Neue gegenwärtig ist. Entscheide nicht überstürzt; höre auf deine Intuition und nimm den Augenblick an. Der leere Ort ist die Pause zwischen den Kapiteln, die fruchtbare Leere, in der noch nichts Gestalt hat. Unter seinem Einfluss ist Klarheit nicht auf Abruf verfügbar; die Lage formt sich noch, und ein zu frühes Drängen auf Auflösung verzerrt nur, was hervortreten will. Dies ist eine Zeit, das Nichtwissen zu ertragen, dem Unbehagen zu widerstehen, das zu vorschnellen Entscheidungen treibt, und darauf zu vertrauen, dass sich der Weg nach vorn zeigt, wenn der Augenblick reift. Der leere Ort belohnt Geduld, inneres Hören und die Bereitschaft, in Offenheit zu verweilen, statt den Raum eilig zu füllen. Wer auf diese Station eingestimmt ist, sollte Ungewissheit nicht als Versagen, sondern als natürliche Phase des Werdens behandeln. Lass den Zwischenraum sein stilles Werk tun; achte auf deine Intuition, die oft am klarsten in der Stille des Noch-Nicht spricht.'),

-- ── Menzil 22 — Kurban Şanslısı / Sad-z-zabih ───────────────
('b1000000-0000-4000-8000-000000000022', 22, 'en', 'The Fortunate of Sacrifice',
 'The station of trial, sacrifice and deep teaching.',
 'This station symbolises a trial and, following it, a profound teaching. It is a hard but soul-ripening period. The Fortunate of Sacrifice names the paradox at the heart of many blessings: that what tests us most is often what teaches us most, and that certain wisdom can only be bought at a price. Under its influence, one may be asked to give something up, to endure a difficulty, or to pass through a hardship that seems to take more than it gives. Yet the name itself holds the promise — this is a *fortunate* sacrifice, one whose eventual fruit is a deepened understanding that no easier road could provide. This is a time to accept the lesson within the loss, to let hardship refine rather than embitter, and to trust that what is surrendered now makes room for a greater maturity. The Fortunate of Sacrifice rewards endurance, humility and the faith to keep learning through pain. Those attuned to this station should not resist the trial but move through it consciously, gathering its teaching. What ripens the soul is rarely comfortable, yet its fruit outlasts the ache of its growing.'),
('b2000000-0000-4000-8000-000000000022', 22, 'de', 'Der Glückliche des Opfers',
 'Die Station der Prüfung, des Opfers und der tiefen Lehre.',
 'Diese Station versinnbildlicht eine Prüfung und, ihr folgend, eine tiefe Lehre. Es ist eine harte, doch die Seele reifende Zeit. Der Glückliche des Opfers benennt das Paradox im Herzen vieler Segnungen: dass gerade das, was uns am meisten prüft, uns oft am meisten lehrt, und dass gewisse Weisheit nur um einen Preis zu erlangen ist. Unter seinem Einfluss mag man aufgefordert sein, etwas aufzugeben, eine Schwierigkeit zu ertragen oder durch eine Härte zu gehen, die mehr zu nehmen als zu geben scheint. Doch der Name selbst birgt die Verheißung — dies ist ein *glückliches* Opfer, dessen schließliche Frucht ein vertieftes Verständnis ist, das kein leichterer Weg gewähren könnte. Dies ist eine Zeit, die Lehre im Verlust anzunehmen, die Härte läutern statt verbittern zu lassen und darauf zu vertrauen, dass das jetzt Hingegebene Raum für eine größere Reife schafft. Der Glückliche des Opfers belohnt Ausdauer, Demut und den Glauben, durch Schmerz weiterzulernen. Wer auf diese Station eingestimmt ist, sollte der Prüfung nicht widerstehen, sondern sie bewusst durchschreiten.'),

-- ── Menzil 23 — Yutma Şanslısı / Sad-bula ───────────────────
('b1000000-0000-4000-8000-000000000023', 23, 'en', 'The Fortunate of Swallowing',
 'The station of forgiveness, closure and inner absorption.',
 'This is a time to forgive the pain of the past, to leave it behind and to absorb it inwardly. The central message of this station is to forgive yourself as well. The Fortunate of Swallowing names the quiet act of taking in what has hurt us, digesting it, and letting it become part of us without letting it poison us. Under its influence, old wounds ask to be released, resentments loosened, and grievances — whether toward others or toward oneself — finally set down. This is not about pretending the hurt never happened, but about metabolising it, drawing from it whatever nourishment it holds and letting the rest dissolve. Forgiveness here is medicine for the one who offers it. The Fortunate of Swallowing rewards compassion, especially the hardest kind: compassion turned inward. Those attuned to this station should make peace with what cannot be changed, release the grip of old anger, and extend to themselves the mercy they would offer a friend. To forgive is to reclaim the energy that grievance consumes. What you finally lay down here you no longer have to carry, and lightness returns where bitterness once lived.'),
('b2000000-0000-4000-8000-000000000023', 23, 'de', 'Der Glückliche des Verschlingens',
 'Die Station der Vergebung, des Abschlusses und der inneren Verinnerlichung.',
 'Dies ist eine Zeit, den Schmerz der Vergangenheit zu vergeben, ihn hinter sich zu lassen und ihn innerlich aufzunehmen. Die zentrale Botschaft dieser Station ist, auch sich selbst zu vergeben. Der Glückliche des Verschlingens benennt den stillen Akt, das aufzunehmen, was uns verletzt hat, es zu verdauen und es zu einem Teil von uns werden zu lassen, ohne dass es uns vergiftet. Unter seinem Einfluss bitten alte Wunden darum, losgelassen zu werden, Groll darum, sich zu lösen, und Kränkungen — ob gegen andere oder gegen sich selbst — darum, endlich abgelegt zu werden. Es geht nicht darum, so zu tun, als sei der Schmerz nie geschehen, sondern ihn zu verstoffwechseln, aus ihm zu ziehen, was er an Nahrung birgt, und den Rest sich auflösen zu lassen. Vergebung ist hier Medizin für den, der sie schenkt. Der Glückliche des Verschlingens belohnt Mitgefühl, besonders die schwerste Art: das nach innen gewandte. Wer auf diese Station eingestimmt ist, sollte Frieden mit dem Unveränderlichen schließen und sich selbst jene Gnade gewähren, die er einem Freund entgegenbrächte.'),

-- ── Menzil 24 — Şansların Şanslısı / Sad-süud ───────────────
('b1000000-0000-4000-8000-000000000024', 24, 'en', 'The Fortunate of Fortunes',
 'The station of fortune opening and glad tidings.',
 'In popular belief this is one of the most fortunate of all the stations. It is favourable for material and spiritual opening, unexpected glad tidings and surprising news. The Fortunate of Fortunes carries the brightest promise of the twenty-eight — a moment when luck itself seems to turn in one''s favour and doors long closed swing open. Under its influence, blessings may arrive without apparent cause, opportunities appear as if summoned, and news that had been awaited (or never dared hoped for) finally comes. This is a time to say yes to good fortune, to remain open to the unexpected gift, and to move forward with the confidence of one whom the tide is carrying. The Fortunate of Fortunes rewards optimism, readiness and gratitude — for luck tends to favour those who greet it with open hands. Those attuned to this station should act on their auspicious feeling, pursue what they desire while the wind is fair, and trust that this is a season of yes. Not every gate opens forever; step through while this one stands wide. What you begin under this fortune carries its blessing forward.'),
('b2000000-0000-4000-8000-000000000024', 24, 'de', 'Der Glückliche der Glücklichen',
 'Die Station des sich öffnenden Glücks und der frohen Botschaft.',
 'Im Volksglauben ist dies eine der glücklichsten aller Stationen. Sie ist günstig für materielle und geistige Öffnung, für unerwartete frohe Botschaft und überraschende Nachrichten. Der Glückliche der Glücklichen trägt die hellste Verheißung der achtundzwanzig — einen Augenblick, in dem das Glück selbst sich zu einem zu wenden scheint und lange verschlossene Türen aufschwingen. Unter seinem Einfluss mögen Segnungen ohne ersichtlichen Grund eintreffen, Gelegenheiten wie herbeigerufen erscheinen und Nachrichten, die erwartet (oder nie zu erhoffen gewagt) wurden, endlich kommen. Dies ist eine Zeit, Ja zum guten Glück zu sagen, offen für das unerwartete Geschenk zu bleiben und mit dem Vertrauen dessen voranzuschreiten, den die Flut trägt. Der Glückliche der Glücklichen belohnt Zuversicht, Bereitschaft und Dankbarkeit — denn das Glück begünstigt jene, die es mit offenen Händen empfangen. Wer auf diese Station eingestimmt ist, sollte seinem günstigen Gefühl folgen und verfolgen, was er ersehnt, solange der Wind günstig steht. Nicht jedes Tor bleibt für immer offen; tritt hindurch, solange dieses weit steht.'),

-- ── Menzil 25 — Çadırların Şanslısı / Sad-ahbiye ────────────
('b1000000-0000-4000-8000-000000000025', 25, 'en', 'The Fortunate of the Tents',
 'The station of home, family and putting down roots.',
 'This is a favourable station for building a home, moving house, marrying or welcoming a new member into the family. It is a time to put down roots. The Fortunate of the Tents gathers the warm energy of belonging — of shelter, kinship and the deep human need for a place to call one''s own. Under its influence, matters of the household and the heart of the family flourish; what is founded now upon love and loyalty tends to endure. This is a time to strengthen the bonds of home, to invest in the spaces and relationships that hold a life together, and to commit to the people who are your foundation. Whether it is a new dwelling, a marriage, a birth or simply a renewed dedication to family, the ground is fertile for rooting. The Fortunate of the Tents rewards loyalty, nurturing and the courage to belong somewhere fully. Those attuned to this station should tend their nest, honour their kin, and build the stable base from which the rest of life can grow. Roots put down now will hold you steady through every later season. Home, well made, becomes the anchor of a whole existence.'),
('b2000000-0000-4000-8000-000000000025', 25, 'de', 'Der Glückliche der Zelte',
 'Die Station des Zuhauses, der Familie und des Wurzelschlagens.',
 'Dies ist eine günstige Station, um ein Zuhause zu gründen, umzuziehen, zu heiraten oder ein neues Mitglied in der Familie willkommen zu heißen. Es ist eine Zeit, Wurzeln zu schlagen. Der Glückliche der Zelte sammelt die warme Energie der Zugehörigkeit — von Obdach, Verwandtschaft und dem tiefen menschlichen Bedürfnis nach einem Ort, den man den eigenen nennen kann. Unter seinem Einfluss gedeihen die Angelegenheiten des Haushalts und des Familienherzens; was jetzt auf Liebe und Treue gegründet wird, hat Bestand. Dies ist eine Zeit, die Bande des Zuhauses zu stärken, in die Räume und Beziehungen zu investieren, die ein Leben zusammenhalten, und sich den Menschen zu verpflichten, die dein Fundament sind. Ob eine neue Wohnstatt, eine Ehe, eine Geburt oder einfach eine erneuerte Hingabe an die Familie — der Boden ist fruchtbar zum Wurzeln. Der Glückliche der Zelte belohnt Treue, Fürsorge und den Mut, irgendwo ganz dazuzugehören. Wer auf diese Station eingestimmt ist, sollte sein Nest hegen und die stabile Basis errichten, aus der das übrige Leben wachsen kann.'),

-- ── Menzil 26 — Ön / Mukaddem ───────────────────────────────
('b1000000-0000-4000-8000-000000000026', 26, 'en', 'The Front',
 'The station of preparation and sowing seeds.',
 'This is a period of preparation for the near future. The seeds planted now will bear fruit in the coming station. Patience and care are important. The Front stands at the leading edge of what is to come — the moment before the moment, when foundations are laid and groundwork is done. Under its influence, results are not yet visible, and that is precisely the point; this is a season of causes, not effects. What you set in motion now, quietly and diligently, is what will ripen later. This is a time to prepare well, to attend to details, to sow with intention and to trust the interval before the harvest. Impatience is the chief temptation here, for the work of preparation offers little immediate reward. Yet the care taken at this stage determines the quality of everything that follows. The Front rewards foresight, diligence and the discipline of doing the unglamorous groundwork. Those attuned to this station should plant their seeds thoughtfully, tend them with patience, and remember that every abundant future was once an invisible beginning. What you build now in quiet becomes what stands tall later in fullness.'),
('b2000000-0000-4000-8000-000000000026', 26, 'de', 'Das Vordere',
 'Die Station der Vorbereitung und des Säens von Samen.',
 'Dies ist eine Zeit der Vorbereitung auf die nahe Zukunft. Die jetzt gepflanzten Samen tragen in der kommenden Station Frucht. Geduld und Sorgfalt sind wichtig. Das Vordere steht an der vordersten Kante dessen, was kommen wird — dem Augenblick vor dem Augenblick, in dem Fundamente gelegt und Grundlagen geschaffen werden. Unter seinem Einfluss sind Ergebnisse noch nicht sichtbar, und genau das ist der Sinn; dies ist eine Zeit der Ursachen, nicht der Wirkungen. Was du jetzt in Gang setzt, still und fleißig, ist das, was später reifen wird. Dies ist eine Zeit, gut vorzubereiten, auf die Einzelheiten zu achten, mit Absicht zu säen und dem Zwischenraum vor der Ernte zu vertrauen. Ungeduld ist hier die Hauptversuchung, denn die Arbeit der Vorbereitung bietet wenig unmittelbaren Lohn. Doch die Sorgfalt dieser Phase bestimmt die Güte all dessen, was folgt. Das Vordere belohnt Weitsicht, Fleiß und die Disziplin, die unscheinbare Grundlagenarbeit zu tun. Wer auf diese Station eingestimmt ist, sollte seine Samen bedacht pflanzen und mit Geduld hegen.'),

-- ── Menzil 27 — Son / Müahhar ───────────────────────────────
('b1000000-0000-4000-8000-000000000027', 27, 'en', 'The Rear',
 'The station of completion, final touches and closure.',
 'This is the ideal station for closing what remains open and consciously ending a cycle. Set aside time for a clear farewell. The Rear stands at the trailing edge of a phase — the moment for finishing rather than starting, for tying loose ends and bringing matters to a proper conclusion. Under its influence, what has been left unresolved presses to be settled, and the satisfaction of completion outweighs the excitement of the new. This is a time to apply the final touches, to honour what has been by concluding it well, and to give endings the care they deserve. A cycle closed cleanly leaves no residue to trouble the next; a farewell said fully frees both the leaving and the staying. The Rear rewards thoroughness, closure and the wisdom to know when something is truly finished. Those attuned to this station should resist the urge to rush ahead and instead complete what stands before them — the last chapter, the final conversation, the parting words. What is ended consciously becomes a foundation rather than a haunting. Give this ending its due, and you step forward unburdened, ready for whatever begins next.'),
('b2000000-0000-4000-8000-000000000027', 27, 'de', 'Das Hintere',
 'Die Station der Vollendung, des letzten Feinschliffs und des Abschlusses.',
 'Dies ist die ideale Station, um das offen Gebliebene zu schließen und einen Zyklus bewusst zu beenden. Nimm dir Zeit für einen klaren Abschied. Das Hintere steht an der hinteren Kante einer Phase — dem Augenblick des Beendens statt des Beginnens, des Verknüpfens loser Enden und des angemessenen Abschließens von Dingen. Unter seinem Einfluss drängt das Ungelöste danach, geregelt zu werden, und die Befriedigung der Vollendung wiegt schwerer als der Reiz des Neuen. Dies ist eine Zeit, den letzten Feinschliff anzubringen, das Gewesene zu ehren, indem man es gut abschließt, und den Enden die Sorgfalt zu geben, die sie verdienen. Ein sauber geschlossener Zyklus hinterlässt keinen Rückstand, der das Nächste stört; ein ganz ausgesprochener Abschied befreit sowohl das Gehende als auch das Bleibende. Das Hintere belohnt Gründlichkeit, Abschluss und die Weisheit zu erkennen, wann etwas wahrhaft beendet ist. Wer auf diese Station eingestimmt ist, sollte dem Drang widerstehen, vorauszueilen, und stattdessen vollenden, was vor ihm liegt.'),

-- ── Menzil 28 — Bağlanan İp / Reşa ──────────────────────────
('b1000000-0000-4000-8000-000000000028', 28, 'en', 'The Binding Cord',
 'The station of solidarity, allegiance and shared purpose.',
 'This is a favourable station for acting not alone but together with a community, a friendship or a partnership. The strength of union. The Binding Cord is that which ties separate strands into a single, stronger whole, and this station celebrates the power that arises when people join toward a common aim. Under its influence, what could not be achieved in isolation becomes possible through cooperation; the burden shared is lightened, and the goal pursued together comes nearer. This is a time to reach for others, to form and honour alliances, to contribute to something larger than yourself and to let others contribute to you. Solidarity here is not the loss of the self but its amplification. The Binding Cord rewards loyalty, collaboration and the humility to recognise that we accomplish most when we accomplish together. Those attuned to this station should seek their companions, strengthen their bonds of allegiance, and pursue their aims in concert rather than in solitude. A single thread frays; a woven cord holds. What you build with others now will carry a strength that no solitary effort could match. In union there is endurance.'),
('b2000000-0000-4000-8000-000000000028', 28, 'de', 'Das bindende Seil',
 'Die Station der Solidarität, der Verbundenheit und des gemeinsamen Ziels.',
 'Dies ist eine günstige Station, um nicht allein, sondern gemeinsam mit einer Gemeinschaft, einer Freundschaft oder einer Partnerschaft zu handeln. Die Kraft der Einheit. Das bindende Seil ist das, was einzelne Stränge zu einem einzigen, stärkeren Ganzen verknüpft, und diese Station feiert die Macht, die entsteht, wenn Menschen sich auf ein gemeinsames Ziel hin vereinen. Unter ihrem Einfluss wird durch Zusammenarbeit möglich, was in der Vereinzelung nicht zu erreichen war; die geteilte Last wird leichter, und das gemeinsam verfolgte Ziel rückt näher. Dies ist eine Zeit, nach anderen zu greifen, Bündnisse zu schließen und zu ehren, zu etwas Größerem als sich selbst beizutragen und andere zu sich beitragen zu lassen. Solidarität ist hier kein Verlust des Selbst, sondern seine Verstärkung. Das bindende Seil belohnt Treue, Zusammenarbeit und die Demut zu erkennen, dass wir am meisten erreichen, wenn wir gemeinsam erreichen. Wer auf diese Station eingestimmt ist, sollte seine Gefährten suchen und seine Ziele im Verbund statt in der Einsamkeit verfolgen. Ein einzelner Faden zerfranst; ein geflochtenes Seil hält.')
ON DUPLICATE KEY UPDATE
  name = VALUES(name),
  short_summary = VALUES(short_summary),
  content = VALUES(content);
